import { Bytes32 } from '../Bytes32.js';
export class TxMsgTransferFungible {
    constructor(to, tokenId, amount) {
        this.to = to;
        this.tokenId = tokenId;
        this.amount = amount;
    }
    write(w) {
        this.to.write(w);
        w.write8u(this.tokenId);
        w.write8u(this.amount);
    }
    read(r) {
        this.to = Bytes32.read(r);
        this.tokenId = r.read8u();
        this.amount = r.read8u();
    }
    static read(r) {
        const v = new TxMsgTransferFungible();
        v.read(r);
        return v;
    }
}
